#include <stdio.h>
#include <errno.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>
int main(void) {
    int fd = open("/tmp/kf_readonly_test.txt", O_CREAT | O_WRONLY, 0444);
    if (fd >= 0) {
        write(fd, "test", 4);
        close(fd);
    }
    errno = 0;
    fd = open("/tmp/kf_readonly_test.txt", O_WRONLY);
    if (fd == -1) {
        printf("Write attempt: %s (errno=%d)\n", strerror(errno), errno);
    } else {
        close(fd);
    }
    printf("EPERM=%d, EACCES=%d\n", EPERM, EACCES);
    unlink("/tmp/kf_readonly_test.txt");
    return 0;
}

